external_knowledge:
; Compatible in this context means that the device can run the specified IGEL OS version without issues; 

; The 'last known user' refers to the user who most recently accessed the device (though technically, the query only guarantees the user with the 'maximum' name among the users who accessed the device, not necessarily the last one due to the use of MAX without timestamp); 

; The 'respective IGEL OS versions' refers to the IGEL OS versions that each device is compatible with.

sql:
SELECT device_id, compatible
FROM device_compatibility
WHERE igel_os_version_id = 1;

SELECT COUNT(*) AS total_supported_devices
FROM device_compatibility
WHERE igel_os_version_id = 1;

SELECT note_text
FROM device_notes
WHERE JULIANDAY('now') - JULIANDAY(updated_at) <= 7;
